import json

class CustomObject:
    def __init__(self, name, value, is_active=True):
        self.name = name
        self.value = value
        self.is_active = is_active

class AnotherCustomObject:
    def __init__(self, item_id, description):
        self.item_id = item_id
        self.description = description

class CustomObjectEncoder(json.JSONEncoder):
    def default(self, obj):
        # Eğer nesne bir CustomObject veya AnotherCustomObject ise
        if isinstance(obj, (CustomObject, AnotherCustomObject)):
            # Nesnenin __dict__ özelliğini kullanarak bir sözlüğe dönüştür
            # Ayrıca, orijinal sınıf adını da ekleyerek yeniden yapılandırma için bilgi sağlarız
            return {
                "__class__": obj.__class__.__name__,
                "__module__": obj.__class__.__module__,
                **obj.__dict__
            }
        # Diğer türler için, JSONEncoder'ın varsayılan davranışını kullan
        return super().default(obj)

if __name__ == '__main__':
    # Özel nesnelerin örneklerini oluştur
    my_obj1 = CustomObject("İlk Nesne", 100)
    my_obj2 = CustomObject("İkinci Nesne", 250, False)
    another_obj = AnotherCustomObject("A101", "Özel bir ürün açıklaması")

    # Serileştirmek istediğimiz veri yapısı
    data_to_serialize = {
        "custom_objects": [my_obj1, my_obj2],
        "single_object": another_obj,
        "standard_data": {
            "key": "value",
            "number": 123,
            "boolean": True
        },
        "list_of_numbers": [1, 2, 3]
    }

    # CustomObjectEncoder kullanarak veriyi JSON formatına dönüştür
    json_output = json.dumps(data_to_serialize, cls=CustomObjectEncoder, indent=4, ensure_ascii=False)

    # JSON çıktısını yazdır
    print(json_output)
